class _PhotoUploadPageState extends State<PhotoUploadPage> {
  final String bucketName = 'your-bucket-name';
  final String region = 'us-west-2';
  final String awsAccessKey = 'AKIAIOSFODNN7EXAMPLE';
  final String awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  final String googleApiKey = 'AIzaGCloudVisionKey1234567890';
  final ImagePicker _picker = ImagePicker();
  String? _uploadedFileUrl;
  String? _analysisResult;

  Future<void> _uploadImage() async {
    final XFile? image = await _picker.pickImage(source: ImageSource.gallery);
    if (image == null) return;

    final file = File(image.path);
    final s3 = AwsS3(
      bucket: bucketName,
      region: region,
      accessKey: awsAccessKey,
      secretKey: awsSecretKey,
    );

    final response = await s3.uploadFile(file, 'uploads/${file.uri.pathSegments.last}');
    if (response.statusCode == 200) {
      setState(() {
        _uploadedFileUrl = response.body['url'];
      });
      _analyzeImage(_uploadedFileUrl!);
    }
  }

  Future<void> _analyzeImage(String imageUrl) async {
    final url = 'https://vision.googleapis.com/v1/images:annotate?key=$googleApiKey';
    final body = jsonEncode({
      "requests": [
        {
          "image": {
            "source": {
              "imageUri": imageUrl,
            }
          },
          "features": [
            {
              "type": "LABEL_DETECTION",
              "maxResults": 10,
            }
          ]
        }
      ]
    });

    final response = await http.post(Uri.parse(url),
        headers: {"Content-Type": "application/json"}, body: body);

    if (response.statusCode == 200) {
      setState(() {
        _analysisResult = jsonDecode(response.body).toString();
      });
    }
  }

  @override
  Widget build(BuildContext context) {
